import React, { useRef, useState } from "react";
import { BrowserRouter as Router, Routes, Route, Navigate, useLocation } from "react-router-dom"; // Import useLocation
import Navbar from "./components/Navbar";
import Home from "./components/Home";
import About from "./components/About";
import PracticeAreas from "./components/PracticeAreas";
import Professionals from "./components/Professionals";
import News from "./components/News";
import Gallery from "./components/Gallery";
import Contact from "./components/Contact";
import AllNews from "./components/AllNews";
import Login from "./components/Login";
import AdminDashboard from "./components/AdminDashboard";
import "./styles.css";

function App() {
  const [auth, setAuth] = useState({
    isAuthenticated: false,
    user: null
  });
  const newsSectionRef = useRef(null);

  // Use location to check the current route, inside the Router context
  const location = useLocation();

  const scrollToNewsSection = () => {
    if (newsSectionRef.current) {
      newsSectionRef.current.scrollIntoView({ behavior: "smooth" });
    }
  };

  return (
    <>
      {/* Conditionally render Navbar based on the current route */}
      {location.pathname !== "/admin/login" && <Navbar auth={auth} setAuth={setAuth} />}

      <Routes>
        {/* Static Routes */}
        <Route
          path="/"
          element={
            <>
              <section id="HOME">
                <Home />
              </section>
              <section id="ABOUT US">
                <About />
              </section>
              <section id="AREAS OF PRACTICE">
                <PracticeAreas />
              </section>
              <section id="OUR PROFESSIONALS">
                <Professionals />
              </section>
              <section id="NEWS & ARTICLES" ref={newsSectionRef}>
                <News />
              </section>
              <section id="GALLERY">
                <Gallery />
              </section>
              <section id="CONTACT US">
                <Contact />
              </section>
            </>
          }
        />

        {/* News Route */}
        <Route
          path="/news"
          element={
            <>
              <section id="HOME">
                <Home />
              </section>
              <section id="ABOUT US">
                <About />
              </section>
              <section id="AREAS OF PRACTICE">
                <PracticeAreas />
              </section>
              <section id="OUR PROFESSIONALS">
                <Professionals />
              </section>
              <section id="NEWS & ARTICLES" ref={newsSectionRef}>
                <News />
              </section>
              <section id="GALLERY">
                <Gallery />
              </section>
              <section id="CONTACT US">
                <Contact />
              </section>
            </>
          }
        />

        {/* More news section */}
        <Route
          path="/more-news"
          element={<AllNews scrollToNewsSection={scrollToNewsSection} />}
        />

        {/* Admin Login Route */}
        <Route
          path="/admin/login"
          element={
            auth.isAuthenticated ? (
              <Navigate to="/admin/dashboard" />
            ) : (
              <Login setAuth={setAuth} />
            )
          }
        />

        {/* Admin Dashboard Route */}
        <Route
          path="/admin/dashboard"
          element={
            auth.isAuthenticated ? (
              <AdminDashboard user={auth.user} />
            ) : (
              <Navigate to="/admin/login" />
            )
          }
        />

        {/* Admin Messages Route */}
        <Route
          path="/admin/messages"
          element={
            auth.isAuthenticated ? (
              <AdminDashboard user={auth.user} />
            ) : (
              <Navigate to="/admin/login" />
            )
          }
        />

        {/* 404 Route */}
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </>
  );
}

export default function Root() {
  return (
    <Router>
      <App />
    </Router>
  );
}
